// Memory Read Operation Sequence
BEGIN
  // Step 1: Load address into MAR
  MAR <- ADDRESS

  // Step 2: Place address on address bus
  ADDRESS_BUS <- MAR

  // Step 3: Assert READ control signal
  READ_SIGNAL <- TRUE

  // Step 4: Wait for memory access (memory cycle time)
  WAIT(MEMORY_CYCLE_TIME)

  // Step 5: Memory places data on data bus
  DATA <- MEMORY[ADDRESS]

  // Step 6: Load data into MDR
  MDR <- DATA

  // Step 7: Transfer data to destination register
  REGISTER <- MDR

  // Step 8: De-assert READ signal
  READ_SIGNAL <- FALSE
END

// PUSH Operation - Save register to stack
PROCEDURE PUSH(register_value)
BEGIN
  // Decrement stack pointer
  SP <- SP - WORD_SIZE

  // Store value at new stack top
  MEMORY[SP] <- register_value
END

// POP Operation - Retrieve value from stack
PROCEDURE POP()
BEGIN
  // Read value from stack top
  temp <- MEMORY[SP]

  // Increment stack pointer
  SP <- SP + WORD_SIZE

  // Return the retrieved value
  RETURN temp
END

// Example: Saving and restoring registers
PROCEDURE FUNCTION_CALL()
BEGIN
  PUSH(R1)      // Save R1
  PUSH(R2)      // Save R2
  // ... function body ...
  POP(R2)       // Restore R2
  POP(R1)       // Restore R1
END

#include <stdio.h>
#include <stdint.h>

#define MEMORY_SIZE 256
typedef uint8_t byte;

// Simulated memory array
byte memory[MEMORY_SIZE];

// Simulated memory read
byte memory_read(uint16_t address) {
    if (address >= MEMORY_SIZE) {
        printf("Error: Address out of bounds\n");
        return 0;
    }
    printf("READ: Address 0x%04X -> Data 0x%02X\n", address, memory[address]);
    return memory[address];
}

// Simulated memory write
void memory_write(uint16_t address, byte data) {
    if (address >= MEMORY_SIZE) {
        printf("Error: Address out of bounds\n");
        return;
    }
    printf("WRITE: Address 0x%04X <- Data 0x%02X\n", address, data);
    memory[address] = data;
}

int main() {
    // Write some data to memory
    memory_write(0x00, 0xAA);
    memory_write(0x01, 0xBB);
    memory_write(0x02, 0xCC);
    memory_write(0x03, 0xDD);

    // Read data back
    byte val1 = memory_read(0x00);
    byte val2 = memory_read(0x01);

    // Store a 32-bit value at address 4
    uint32_t num = 0x12345678;
    memory_write(0x04, (num >> 0) & 0xFF);   // Little-endian
    memory_write(0x05, (num >> 8) & 0xFF);
    memory_write(0x06, (num >> 16) & 0xFF);
    memory_write(0x07, (num >> 24) & 0xFF);

    return 0;
}
